import React, { useEffect, useState } from 'react';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box } from '@material-ui/core';
import { getItems, createItem } from '../services/ApiService';

export default function ItemManagement() {
  const [items, setItems] = useState([]);
  const [newItem, setNewItem] = useState({ name: '', retailPrice: 0, wholesalePrice: 0, stock: 0 });

  useEffect(() => {
    getItems().then(res => setItems(res.data));
  }, []);

  const addItem = () => {
    createItem(newItem).then(res => {
      setItems([...items, res.data]);
      setNewItem({ name: '', retailPrice: 0, wholesalePrice: 0, stock: 0 });
    });
  };

  return (
    <div>
      <Box marginBottom={2}>
        <TextField
          label="Item Name"
          value={newItem.name}
          onChange={e => setNewItem({ ...newItem, name: e.target.value })}
        />
        <TextField
          label="Retail Price"
          type="number"
          value={newItem.retailPrice}
          onChange={e => setNewItem({ ...newItem, retailPrice: parseFloat(e.target.value) })}
        />
        <TextField
          label="Wholesale Price"
          type="number"
          value={newItem.wholesalePrice}
          onChange={e => setNewItem({ ...newItem, wholesalePrice: parseFloat(e.target.value) })}
        />
        <TextField
          label="Stock"
          type="number"
          value={newItem.stock}
          onChange={e => setNewItem({ ...newItem, stock: parseInt(e.target.value) })}
        />
        <Button onClick={addItem} color="primary" variant="contained">Add Item</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
            <TableCell>Retail Price</TableCell>
            <TableCell>Wholesale Price</TableCell>
            <TableCell>Stock</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {items.map(item => (
            <TableRow key={item.id}>
              <TableCell>{item.name}</TableCell>
              <TableCell>{item.retailPrice}</TableCell>
              <TableCell>{item.wholesalePrice}</TableCell>
              <TableCell>{item.stock}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
